// 파일 위치: app/mypage/page.tsx
// 용도: 마이페이지 - 프로필 이미지 업로드 + 닉네임 수정 + 내가 쓴 글·댓글 탭
// Supabase Storage 'avatars' 버킷에 이미지 업로드 → profiles.avatar_url 업데이트
// 프로필 이미지 업로드 시 browser-image-compression으로 자동 압축
//   → 썸네일 용도이므로 maxSizeMB: 0.5 / maxWidthOrHeight: 800
// 브랜드: 형광 그린 #73e346 계열 다크 테마

"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { supabase } from "@/utils/supabase/client";
import imageCompression from "browser-image-compression";
import {
  User,
  BadgeCheck,
  Pencil,
  X,
  Save,
  Loader2,
  FileText,
  MessageCircle,
  Phone,
  Mail,
  Building2,
  Briefcase,
  Heart,
  ArrowBigUp,
  Clock,
  Camera,
  ImagePlus,
} from "lucide-react";
import type { User as SupabaseUser } from "@supabase/supabase-js";

// ═══════════════════════════════════════════════════════
// 프로필 이미지 압축 옵션
// 썸네일 용도이므로 게시글보다 더 강력하게 압축
// maxSizeMB: 0.5 (500KB), maxWidthOrHeight: 800px
// ═══════════════════════════════════════════════════════
const AVATAR_COMPRESSION_OPTIONS = {
  maxSizeMB: 0.5, // 압축 후 최대 500KB
  maxWidthOrHeight: 800, // 가로 또는 세로 최대 800px
  useWebWorker: true, // 웹 워커 사용 (메인 스레드 블로킹 방지)
};

// ─── 프로필 타입 정의 ───
type Profile = {
  id: string;
  nickname: string;
  avatar_url: string | null;
  bio: string;
  status_message: string;
  industry: string;
  company: string;
  phone: string;
  interests: string[];
  is_company_verified: boolean;
  is_business_verified: boolean;
  created_at: string;
};

// ─── 내가 쓴 글 타입 ───
type MyPost = {
  id: string;
  title: string;
  content: string;
  category: string;
  upvotes: number;
  comment_count: number;
  created_at: string;
};

// ─── 내가 단 댓글 타입 (게시글 제목 포함) ───
type MyComment = {
  id: string;
  post_id: string;
  content: string;
  created_at: string;
  posts: { title: string } | { title: string }[] | null;
};

// ─── 카테고리 색상 매핑 (다크 테마) ───
function getCategoryColor(category: string): string {
  const colorMap: Record<string, string> = {
    사업: "bg-primary/20 text-primary-light",
    마케팅: "bg-purple-500/20 text-purple-400",
    커리어: "bg-cyan-500/20 text-cyan-400",
    자유: "bg-amber-500/20 text-amber-400",
  };
  return colorMap[category] || "bg-gray-500/20 text-gray-400";
}

// ─── 날짜 포맷 함수 ───
function timeAgo(dateString: string): string {
  const now = new Date();
  const past = new Date(dateString);
  const diffMs = now.getTime() - past.getTime();
  const diffMin = Math.floor(diffMs / 60000);
  const diffHour = Math.floor(diffMs / 3600000);
  const diffDay = Math.floor(diffMs / 86400000);
  if (diffMin < 1) return "방금 전";
  if (diffMin < 60) return `${diffMin}분 전`;
  if (diffHour < 24) return `${diffHour}시간 전`;
  if (diffDay < 30) return `${diffDay}일 전`;
  return `${Math.floor(diffDay / 30)}개월 전`;
}

// ─── 관심사 프리셋 목록 ───
const INTEREST_OPTIONS = [
  "스타트업", "마케팅", "투자", "개발", "디자인", "AI",
  "커머스", "콘텐츠", "HR", "재무", "법률", "부동산",
];

// ─── 업종 프리셋 목록 ───
const INDUSTRY_OPTIONS = [
  "IT/소프트웨어", "금융/핀테크", "커머스/유통", "교육/에듀테크",
  "F&B/외식", "제조업", "미디어/콘텐츠", "헬스케어", "부동산", "기타",
];

export default function MyPage() {
  // ─── 상태 관리 ───
  const [user, setUser] = useState<SupabaseUser | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  // 이미지 업로드 관련 상태
  const [uploading, setUploading] = useState(false);
  // 이미지 압축 진행 중 상태 (압축 중에는 버튼 비활성화 + "이미지 최적화 중..." 표시)
  const [compressingAvatar, setCompressingAvatar] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // 수정 폼 상태
  const [editNickname, setEditNickname] = useState("");
  const [editBio, setEditBio] = useState("");
  const [editStatusMessage, setEditStatusMessage] = useState("");
  const [editIndustry, setEditIndustry] = useState("");
  const [editCompany, setEditCompany] = useState("");
  const [editPhone, setEditPhone] = useState("");
  const [editInterests, setEditInterests] = useState<string[]>([]);

  // 탭 상태
  const [activeTab, setActiveTab] = useState<"posts" | "comments">("posts");
  const [myPosts, setMyPosts] = useState<MyPost[]>([]);
  const [postsLoading, setPostsLoading] = useState(false);

  // 내가 단 댓글 목록
  const [myComments, setMyComments] = useState<MyComment[]>([]);
  const [commentsLoading, setCommentsLoading] = useState(false);

  // 팔로워/팔로잉 숫자
  const [followerCount, setFollowerCount] = useState(0);
  const [followingCount, setFollowingCount] = useState(0);

  const router = useRouter();

  // ─── 프로필 데이터 불러오기 ───
  const fetchProfile = useCallback(async (userId: string) => {
    const { data, error: fetchError } = await supabase
      .from("profiles")
      .select("*")
      .eq("id", userId)
      .single();

    if (fetchError || !data) {
      // 프로필이 없으면 기본 생성
      const defaultNickname =
        (await supabase.auth.getUser()).data.user?.email?.split("@")[0] || "익명";
      const { data: newProfile } = await supabase
        .from("profiles")
        .insert({ id: userId, nickname: defaultNickname })
        .select()
        .single();
      if (newProfile) setProfile(newProfile as Profile);
    } else {
      const profileData = {
        ...data,
        interests: data.interests || [],
        status_message: data.status_message || "",
        industry: data.industry || "",
        company: data.company || "",
        phone: data.phone || "",
        is_company_verified: data.is_company_verified || false,
        is_business_verified: data.is_business_verified || false,
      };
      setProfile(profileData as Profile);
    }
  }, []);

  // ─── 팔로워/팔로잉 숫자 불러오기 ───
  const fetchFollowCounts = useCallback(async (userId: string) => {
    const { count: followers } = await supabase
      .from("follows")
      .select("*", { count: "exact", head: true })
      .eq("following_id", userId);

    const { count: following } = await supabase
      .from("follows")
      .select("*", { count: "exact", head: true })
      .eq("follower_id", userId);

    setFollowerCount(followers || 0);
    setFollowingCount(following || 0);
  }, []);

  // ─── 내가 쓴 글 불러오기 ───
  const fetchMyPosts = useCallback(async (userId: string) => {
    setPostsLoading(true);
    const { data } = await supabase
      .from("posts")
      .select("id, title, content, category, upvotes, comment_count, created_at")
      .eq("author_id", userId)
      .order("created_at", { ascending: false })
      .limit(20);

    setMyPosts((data as MyPost[]) || []);
    setPostsLoading(false);
  }, []);

  // ─── 내가 단 댓글 불러오기 ───
  const fetchMyComments = useCallback(async (userId: string) => {
    setCommentsLoading(true);
    const { data } = await supabase
      .from("comments")
      .select(`id, post_id, content, created_at, posts ( title )`)
      .eq("user_id", userId)
      .order("created_at", { ascending: false })
      .limit(20);

    setMyComments((data as MyComment[]) || []);
    setCommentsLoading(false);
  }, []);

  // ─── 마운트 시 인증 확인 + 데이터 로드 ───
  useEffect(() => {
    const init = async () => {
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session) {
        router.replace("/login");
        return;
      }

      setUser(session.user);
      await Promise.all([
        fetchProfile(session.user.id),
        fetchFollowCounts(session.user.id),
        fetchMyPosts(session.user.id),
        fetchMyComments(session.user.id),
      ]);
      setAuthLoading(false);
    };

    init();
  }, [router, fetchProfile, fetchFollowCounts, fetchMyPosts, fetchMyComments]);

  // ─── 수정 모드 진입 시 현재 값으로 폼 채우기 ───
  const startEditing = () => {
    if (!profile) return;
    setEditNickname(profile.nickname);
    setEditBio(profile.bio || "");
    setEditStatusMessage(profile.status_message);
    setEditIndustry(profile.industry);
    setEditCompany(profile.company);
    setEditPhone(profile.phone);
    setEditInterests([...profile.interests]);
    setIsEditing(true);
    setError("");
    setSuccess("");
  };

  // ─── 관심사 토글 ───
  const toggleInterest = (interest: string) => {
    setEditInterests((prev) =>
      prev.includes(interest)
        ? prev.filter((i) => i !== interest)
        : prev.length < 5
          ? [...prev, interest]
          : prev
    );
  };

  // ═══════════════════════════════════════════════════════
  // 프로필 이미지 업로드 핸들러 (browser-image-compression 적용)
  // 흐름:
  //   1. 파일 선택
  //   2. 이미지 타입/크기 검증
  //   3. browser-image-compression으로 자동 압축 (0.5MB / 800px)
  //   4. 압축된 파일을 Supabase Storage 'avatars' 버킷에 업로드
  //   5. public URL 획득 → profiles.avatar_url 업데이트
  //   6. user_metadata에도 avatar_url 저장
  // ═══════════════════════════════════════════════════════
  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;

    // 파일 타입 검증 (이미지만 허용)
    if (!file.type.startsWith("image/")) {
      setError("이미지 파일만 업로드할 수 있습니다. (jpg, png, gif, webp)");
      return;
    }

    // 원본 파일 크기 제한 (10MB — 압축 전 허용 범위를 넓혀서 UX 개선)
    if (file.size > 10 * 1024 * 1024) {
      setError("이미지 크기는 10MB 이하만 가능합니다.");
      return;
    }

    setUploading(true);
    setCompressingAvatar(true);
    setError("");

    try {
      // ─── Step 1: 이미지 압축 (프로필 썸네일용으로 더 강력하게) ───
      // maxSizeMB: 0.5 (500KB), maxWidthOrHeight: 800px
      let compressedFile: File;
      try {
        const compressedBlob = await imageCompression(
          file,
          AVATAR_COMPRESSION_OPTIONS
        );
        // Blob → File 변환 (Supabase Storage는 File 객체를 기대)
        compressedFile = new File(
          [compressedBlob],
          file.name,
          { type: compressedBlob.type, lastModified: Date.now() }
        );
      } catch {
        // 압축 실패 시 원본 그대로 사용
        compressedFile = file;
      }

      setCompressingAvatar(false); // 압축 완료, 업로드 단계로 전환

      // ─── Step 2: Supabase Storage에 업로드 ───
      const fileExt = file.name.split(".").pop()?.toLowerCase() || "jpg";
      // 유저 ID 기반 고유 파일명 (덮어쓰기 방식으로 스토리지 절약)
      const filePath = `${user.id}/avatar.${fileExt}`;

      const { error: uploadError } = await supabase.storage
        .from("avatars")
        .upload(filePath, compressedFile, {
          cacheControl: "3600",
          upsert: true, // 같은 경로면 덮어쓰기
        });

      if (uploadError) {
        setError("이미지 업로드에 실패했습니다: " + uploadError.message);
        return;
      }

      // ─── Step 3: 업로드된 파일의 공개 URL 획득 ───
      const { data: urlData } = supabase.storage
        .from("avatars")
        .getPublicUrl(filePath);

      const publicUrl = urlData.publicUrl;

      // 캐시 무효화를 위해 타임스탬프 쿼리 파라미터 추가
      const avatarUrlWithCache = `${publicUrl}?t=${Date.now()}`;

      // ─── Step 4: profiles 테이블의 avatar_url 업데이트 ───
      const { error: dbError } = await supabase
        .from("profiles")
        .update({ avatar_url: avatarUrlWithCache })
        .eq("id", user.id);

      if (dbError) {
        setError("프로필 업데이트에 실패했습니다: " + dbError.message);
        return;
      }

      // ─── Step 5: Supabase Auth user_metadata에도 avatar_url 저장 ───
      // (Header 등에서 빠르게 접근하기 위함)
      await supabase.auth.updateUser({
        data: { avatar_url: avatarUrlWithCache },
      });

      // 프로필 새로고침
      await fetchProfile(user.id);
      setSuccess("프로필 이미지가 변경되었습니다!");
      setTimeout(() => setSuccess(""), 3000);
    } catch {
      setError("네트워크 오류가 발생했습니다. 다시 시도해주세요.");
    } finally {
      setUploading(false);
      setCompressingAvatar(false);
      // file input 초기화 (같은 파일 재선택 가능하도록)
      if (fileInputRef.current) {
        fileInputRef.current.value = "";
      }
    }
  };

  // ─── 프로필 저장 핸들러 ───
  const handleSave = async () => {
    if (!user) return;
    setError("");
    setSaving(true);

    if (!editNickname.trim()) {
      setError("닉네임을 입력해주세요.");
      setSaving(false);
      return;
    }

    const { error: updateError } = await supabase
      .from("profiles")
      .update({
        nickname: editNickname.trim(),
        bio: editBio.trim(),
        status_message: editStatusMessage.trim(),
        industry: editIndustry,
        company: editCompany.trim(),
        phone: editPhone.trim(),
        interests: editInterests,
      })
      .eq("id", user.id);

    if (updateError) {
      setError("저장에 실패했습니다: " + updateError.message);
    } else {
      // user_metadata에도 닉네임 동기화
      await supabase.auth.updateUser({
        data: { nickname: editNickname.trim() },
      });

      setSuccess("프로필이 업데이트되었습니다.");
      setIsEditing(false);
      await fetchProfile(user.id);
      setTimeout(() => setSuccess(""), 3000);
    }

    setSaving(false);
  };

  // ─── 로딩 화면 ───
  if (authLoading) {
    return (
      <div className="flex min-h-[calc(100vh-48px)] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  const avatarInitial = user?.email?.charAt(0).toUpperCase() || "?";

  // 아바타 버튼 비활성화 조건: 업로드 중이거나 압축 진행 중
  const isAvatarBusy = uploading || compressingAvatar;

  return (
    <div className="mx-auto max-w-3xl px-4 py-6 md:px-8">
      {/* ═══════════════════════════════════════════════════════ */}
      {/* 프로필 헤더 섹션 (다크 테마)                              */}
      {/* ═══════════════════════════════════════════════════════ */}
      <div className="mb-6 rounded-xl border border-border-color bg-card-bg p-6">
        <div className="flex flex-col gap-6 sm:flex-row sm:items-start">
          {/* 프로필 아바타 (클릭하면 이미지 업로드) */}
          <div className="flex flex-col items-center gap-2">
            {/* 숨겨진 파일 입력 (이미지만 허용) */}
            <input
              ref={fileInputRef}
              type="file"
              accept="image/jpeg,image/png,image/gif,image/webp"
              onChange={handleAvatarUpload}
              className="hidden"
              aria-label="프로필 이미지 업로드"
            />

            {/* 아바타 원형 버튼 — 클릭 시 파일 선택 창 열림 */}
            <button
              onClick={() => fileInputRef.current?.click()}
              disabled={isAvatarBusy}
              className="group relative flex h-24 w-24 items-center justify-center rounded-full overflow-hidden shadow-lg transition-all hover:shadow-primary/30 disabled:opacity-60"
              aria-label="프로필 이미지 변경"
            >
              {/* 프로필 이미지 또는 이니셜 */}
              {profile?.avatar_url ? (
                <img
                  src={profile.avatar_url}
                  alt="프로필 이미지"
                  className="h-full w-full object-cover"
                />
              ) : (
                <div className="flex h-full w-full items-center justify-center bg-gradient-to-br from-primary to-primary-light text-4xl font-bold text-white">
                  {avatarInitial}
                </div>
              )}

              {/* 호버 오버레이 (카메라 아이콘 + 텍스트) */}
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/50 opacity-0 transition-opacity group-hover:opacity-100">
                {isAvatarBusy ? (
                  <Loader2 className="h-6 w-6 animate-spin text-white" />
                ) : (
                  <>
                    <Camera className="h-5 w-5 text-white" />
                    <span className="mt-1 text-[10px] font-medium text-white">
                      변경
                    </span>
                  </>
                )}
              </div>
            </button>

            {/* 업로드/압축 중 상태 표시 */}
            {compressingAvatar && (
              <span className="flex items-center gap-1 text-xs text-primary">
                <Loader2 className="h-3 w-3 animate-spin" />
                이미지 최적화 중...
              </span>
            )}
            {uploading && !compressingAvatar && (
              <span className="text-xs text-primary">업로드 중...</span>
            )}
          </div>

          {/* 프로필 정보 */}
          <div className="flex-1 min-w-0">
            <div className="mb-2 flex items-center gap-2 flex-wrap">
              <h1 className="text-2xl font-bold text-foreground">
                {profile?.nickname || "익명"}
              </h1>

              {profile?.is_company_verified && (
                <span className="flex items-center gap-0.5 rounded-full bg-blue-500/20 px-2 py-0.5 text-xs font-medium text-blue-400" title="회사 인증 완료">
                  <BadgeCheck className="h-3.5 w-3.5" />
                  회사인증
                </span>
              )}

              {profile?.is_business_verified && (
                <span className="flex items-center gap-0.5 rounded-full bg-green-500/20 px-2 py-0.5 text-xs font-medium text-green-400" title="사업자 인증 완료">
                  <BadgeCheck className="h-3.5 w-3.5" />
                  사업자인증
                </span>
              )}

              {!profile?.is_company_verified && !profile?.is_business_verified && (
                <span className="text-xs text-muted">미인증</span>
              )}

              {!isEditing && (
                <button
                  onClick={startEditing}
                  className="ml-auto flex items-center gap-1 rounded-full border border-border-color px-3 py-1 text-sm font-medium text-muted hover:bg-hover-bg hover:text-foreground"
                >
                  <Pencil className="h-3.5 w-3.5" />
                  프로필 수정
                </button>
              )}
            </div>

            {profile?.status_message && (
              <p className="mb-2 text-sm text-muted italic">
                &quot;{profile.status_message}&quot;
              </p>
            )}

            {profile?.bio && (
              <p className="mb-3 text-sm leading-relaxed text-foreground">
                {profile.bio}
              </p>
            )}

            <div className="mb-3 flex flex-wrap items-center gap-3 text-sm text-muted">
              {profile?.industry && (
                <span className="flex items-center gap-1">
                  <Briefcase className="h-3.5 w-3.5" />
                  {profile.industry}
                </span>
              )}
              {profile?.company && (
                <span className="flex items-center gap-1">
                  <Building2 className="h-3.5 w-3.5" />
                  {profile.company}
                </span>
              )}
            </div>

            <div className="flex gap-5 text-sm">
              <div className="text-center">
                <span className="font-bold text-foreground">{myPosts.length}</span>
                <span className="ml-1 text-muted">게시글</span>
              </div>
              <div className="text-center">
                <span className="font-bold text-foreground">{followerCount}</span>
                <span className="ml-1 text-muted">팔로워</span>
              </div>
              <div className="text-center">
                <span className="font-bold text-foreground">{followingCount}</span>
                <span className="ml-1 text-muted">팔로잉</span>
              </div>
            </div>

            {profile?.interests && profile.interests.length > 0 && (
              <div className="mt-3 flex flex-wrap gap-1.5">
                {profile.interests.map((tag) => (
                  <span
                    key={tag}
                    className="flex items-center gap-1 rounded-full bg-primary/20 px-2.5 py-0.5 text-xs font-medium text-primary"
                  >
                    <Heart className="h-3 w-3" />
                    {tag}
                  </span>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ═══════════════════════════════════════════════════════ */}
      {/* 프로필 수정 폼 (다크 테마)                               */}
      {/* ═══════════════════════════════════════════════════════ */}
      {isEditing && (
        <div className="mb-6 rounded-xl border border-primary/30 bg-primary/5 p-6">
          <div className="mb-4 flex items-center justify-between">
            <h2 className="text-lg font-bold text-foreground">프로필 수정</h2>
            <button
              onClick={() => setIsEditing(false)}
              className="rounded-full p-1.5 text-muted hover:bg-hover-bg hover:text-foreground"
              aria-label="닫기"
            >
              <X className="h-5 w-5" />
            </button>
          </div>

          {error && (
            <div className="mb-4 rounded-lg border border-red-500/30 bg-red-500/10 px-4 py-3 text-sm text-red-400">
              {error}
            </div>
          )}

          <div className="space-y-4">
            {/* 프로필 이미지 변경 (수정 모드 내) */}
            <div>
              <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                <ImagePlus className="h-4 w-4 text-muted" />
                프로필 이미지
              </label>
              <div className="flex items-center gap-4">
                <button
                  onClick={() => fileInputRef.current?.click()}
                  disabled={isAvatarBusy}
                  className="group relative flex h-16 w-16 items-center justify-center rounded-full overflow-hidden border-2 border-dashed border-border-color hover:border-primary transition-colors disabled:opacity-60"
                >
                  {profile?.avatar_url ? (
                    <img
                      src={profile.avatar_url}
                      alt="프로필"
                      className="h-full w-full object-cover"
                    />
                  ) : (
                    <Camera className="h-5 w-5 text-muted group-hover:text-primary" />
                  )}
                  {isAvatarBusy && (
                    <div className="absolute inset-0 flex items-center justify-center bg-black/50">
                      <Loader2 className="h-5 w-5 animate-spin text-white" />
                    </div>
                  )}
                </button>
                <div className="text-xs text-muted">
                  {compressingAvatar ? (
                    <p className="flex items-center gap-1 text-primary font-medium">
                      <Loader2 className="h-3 w-3 animate-spin" />
                      이미지 최적화 중...
                    </p>
                  ) : uploading ? (
                    <p className="text-primary font-medium">업로드 중...</p>
                  ) : (
                    <>
                      <p>JPG, PNG, GIF, WebP (자동 압축)</p>
                      <p className="mt-0.5">클릭하여 이미지를 변경하세요</p>
                    </>
                  )}
                </div>
              </div>
            </div>

            {/* 닉네임 */}
            <div>
              <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                <User className="h-4 w-4 text-muted" />
                닉네임
              </label>
              <input
                type="text"
                value={editNickname}
                onChange={(e) => setEditNickname(e.target.value)}
                maxLength={20}
                className="w-full rounded-lg border border-border-color bg-input-bg px-4 py-2.5 text-sm text-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              />
            </div>

            {/* 상태 메시지 */}
            <div>
              <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                <MessageCircle className="h-4 w-4 text-muted" />
                상태 메시지
              </label>
              <input
                type="text"
                value={editStatusMessage}
                onChange={(e) => setEditStatusMessage(e.target.value)}
                placeholder="현재 상태를 한줄로 표현해보세요"
                maxLength={50}
                className="w-full rounded-lg border border-border-color bg-input-bg px-4 py-2.5 text-sm text-foreground placeholder-muted focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              />
            </div>

            {/* 자기소개 */}
            <div>
              <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                <FileText className="h-4 w-4 text-muted" />
                자기소개
              </label>
              <textarea
                value={editBio}
                onChange={(e) => setEditBio(e.target.value)}
                placeholder="간단한 자기소개를 작성해보세요"
                rows={3}
                maxLength={200}
                className="w-full resize-none rounded-lg border border-border-color bg-input-bg px-4 py-2.5 text-sm text-foreground placeholder-muted focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              />
            </div>

            {/* 업종 + 회사 (2열) */}
            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
              <div>
                <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                  <Briefcase className="h-4 w-4 text-muted" />
                  업종
                </label>
                <select
                  value={editIndustry}
                  onChange={(e) => setEditIndustry(e.target.value)}
                  className="w-full rounded-lg border border-border-color bg-input-bg px-4 py-2.5 text-sm text-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                >
                  <option value="">선택하세요</option>
                  {INDUSTRY_OPTIONS.map((opt) => (
                    <option key={opt} value={opt}>
                      {opt}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                  <Building2 className="h-4 w-4 text-muted" />
                  회사명
                </label>
                <input
                  type="text"
                  value={editCompany}
                  onChange={(e) => setEditCompany(e.target.value)}
                  placeholder="회사명 (선택)"
                  maxLength={30}
                  className="w-full rounded-lg border border-border-color bg-input-bg px-4 py-2.5 text-sm text-foreground placeholder-muted focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                />
              </div>
            </div>

            {/* 이메일 (읽기 전용) + 휴대폰 (2열) */}
            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
              <div>
                <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                  <Mail className="h-4 w-4 text-muted" />
                  이메일
                </label>
                <input
                  type="email"
                  value={user?.email || ""}
                  disabled
                  className="w-full rounded-lg border border-border-color bg-hover-bg px-4 py-2.5 text-sm text-muted"
                />
              </div>
              <div>
                <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                  <Phone className="h-4 w-4 text-muted" />
                  휴대폰
                </label>
                <input
                  type="tel"
                  value={editPhone}
                  onChange={(e) => setEditPhone(e.target.value)}
                  placeholder="010-1234-5678"
                  maxLength={13}
                  className="w-full rounded-lg border border-border-color bg-input-bg px-4 py-2.5 text-sm text-foreground placeholder-muted focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                />
              </div>
            </div>

            {/* 관심사 태그 선택 */}
            <div>
              <label className="mb-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground">
                <Heart className="h-4 w-4 text-muted" />
                관심사 (최대 5개)
              </label>
              <div className="flex flex-wrap gap-2">
                {INTEREST_OPTIONS.map((interest) => (
                  <button
                    key={interest}
                    type="button"
                    onClick={() => toggleInterest(interest)}
                    className={`rounded-full px-3 py-1 text-xs font-medium transition-all ${
                      editInterests.includes(interest)
                        ? "bg-primary text-black"
                        : "border border-border-color text-muted hover:border-primary hover:text-primary"
                    }`}
                  >
                    {interest}
                  </button>
                ))}
              </div>
            </div>

            {/* 저장 / 취소 버튼 */}
            <div className="flex justify-end gap-3 border-t border-border-color pt-4">
              <button
                onClick={() => setIsEditing(false)}
                className="rounded-lg px-5 py-2.5 text-sm font-medium text-muted hover:bg-hover-bg hover:text-foreground"
              >
                취소
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="flex items-center gap-2 rounded-lg bg-primary px-6 py-2.5 text-sm font-medium text-black hover:bg-primary-hover disabled:opacity-60"
              >
                {saving ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin" />
                    저장 중...
                  </>
                ) : (
                  <>
                    <Save className="h-4 w-4" />
                    저장하기
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 에러 메시지 (수정 모드가 아닐 때) */}
      {error && !isEditing && (
        <div className="mb-4 rounded-lg border border-red-500/30 bg-red-500/10 px-4 py-3 text-sm text-red-400">
          {error}
        </div>
      )}

      {/* 수정 완료 성공 메시지 */}
      {success && !isEditing && (
        <div className="mb-4 rounded-lg border border-green-500/30 bg-green-500/10 px-4 py-3 text-sm text-green-400">
          {success}
        </div>
      )}

      {/* ═══════════════════════════════════════════════════════ */}
      {/* 하단 탭 섹션 (다크 테마)                                 */}
      {/* ═══════════════════════════════════════════════════════ */}
      <div className="rounded-xl border border-border-color bg-card-bg overflow-hidden">
        {/* 탭 헤더 */}
        <div className="flex border-b border-border-color">
          <button
            onClick={() => setActiveTab("posts")}
            className={`flex flex-1 items-center justify-center gap-2 py-3 text-sm font-medium transition-all ${
              activeTab === "posts"
                ? "border-b-2 border-primary text-primary"
                : "text-muted hover:bg-hover-bg hover:text-foreground"
            }`}
          >
            <FileText className="h-4 w-4" />
            내가 쓴 글
            <span className="rounded-full bg-hover-bg px-2 py-0.5 text-xs">
              {myPosts.length}
            </span>
          </button>
          <button
            onClick={() => setActiveTab("comments")}
            className={`flex flex-1 items-center justify-center gap-2 py-3 text-sm font-medium transition-all ${
              activeTab === "comments"
                ? "border-b-2 border-primary text-primary"
                : "text-muted hover:bg-hover-bg hover:text-foreground"
            }`}
          >
            <MessageCircle className="h-4 w-4" />
            내가 단 댓글
            <span className="rounded-full bg-hover-bg px-2 py-0.5 text-xs">
              {myComments.length}
            </span>
          </button>
        </div>

        {/* 탭 콘텐츠 */}
        <div className="p-4">
          {activeTab === "posts" && (
            <>
              {postsLoading ? (
                <div className="flex justify-center py-8">
                  <Loader2 className="h-6 w-6 animate-spin text-primary" />
                </div>
              ) : myPosts.length === 0 ? (
                <div className="py-12 text-center">
                  <FileText className="mx-auto mb-3 h-10 w-10 text-muted" />
                  <p className="mb-1 text-sm font-medium text-foreground">
                    아직 작성한 글이 없습니다
                  </p>
                  <p className="mb-4 text-xs text-muted">
                    첫 번째 글을 작성해보세요!
                  </p>
                  <a
                    href="/submit"
                    className="inline-block rounded-full bg-primary px-5 py-2 text-sm font-medium text-black hover:bg-primary-hover"
                  >
                    글쓰기
                  </a>
                </div>
              ) : (
                <div className="space-y-3">
                  {myPosts.map((post) => (
                    <Link
                      key={post.id}
                      href={`/post/${post.id}`}
                      className="block rounded-lg border border-border-color p-3 hover:border-muted cursor-pointer transition-colors"
                    >
                      <div className="mb-1 flex items-center gap-2 text-xs">
                        <span
                          className={`rounded-full px-2 py-0.5 font-medium ${getCategoryColor(post.category)}`}
                        >
                          {post.category}
                        </span>
                        <span className="flex items-center gap-1 text-muted">
                          <Clock className="h-3 w-3" />
                          {timeAgo(post.created_at)}
                        </span>
                      </div>
                      <h3 className="mb-1 text-sm font-semibold text-foreground">
                        {post.title}
                      </h3>
                      <p className="mb-2 line-clamp-1 text-xs text-muted">
                        {post.content}
                      </p>
                      <div className="flex items-center gap-3 text-xs text-muted">
                        <span className="flex items-center gap-1">
                          <ArrowBigUp className="h-3.5 w-3.5" />
                          {post.upvotes}
                        </span>
                        <span className="flex items-center gap-1">
                          <MessageCircle className="h-3.5 w-3.5" />
                          {post.comment_count}
                        </span>
                      </div>
                    </Link>
                  ))}
                </div>
              )}
            </>
          )}

          {activeTab === "comments" && (
            <>
              {commentsLoading ? (
                <div className="flex justify-center py-8">
                  <Loader2 className="h-6 w-6 animate-spin text-primary" />
                </div>
              ) : myComments.length === 0 ? (
                <div className="py-12 text-center">
                  <MessageCircle className="mx-auto mb-3 h-10 w-10 text-muted" />
                  <p className="mb-1 text-sm font-medium text-foreground">
                    아직 작성한 댓글이 없습니다
                  </p>
                  <p className="text-xs text-muted">
                    게시글에 댓글을 남겨보세요!
                  </p>
                </div>
              ) : (
                <div className="space-y-3">
                  {myComments.map((comment) => {
                    // posts가 배열일 수도 있고 객체일 수도 있으므로 안전하게 처리
                    const postTitle = comment.posts
                      ? Array.isArray(comment.posts)
                        ? comment.posts[0]?.title || "삭제된 게시글"
                        : comment.posts.title || "삭제된 게시글"
                      : "삭제된 게시글";

                    return (
                      <Link
                        key={comment.id}
                        href={`/post/${comment.post_id}`}
                        className="block rounded-lg border border-border-color p-3 hover:border-muted cursor-pointer transition-colors"
                      >
                        {/* 원본 게시글 제목 */}
                        <div className="mb-1.5 flex items-center gap-2 text-xs text-muted">
                          <FileText className="h-3 w-3" />
                          <span className="truncate">{postTitle}</span>
                          <span className="flex items-center gap-1 ml-auto shrink-0">
                            <Clock className="h-3 w-3" />
                            {timeAgo(comment.created_at)}
                          </span>
                        </div>
                        {/* 내 댓글 내용 */}
                        <p className="text-sm text-foreground line-clamp-2 whitespace-pre-wrap">
                          {comment.content}
                        </p>
                      </Link>
                    );
                  })}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
